solutions.python:
class Solution:
    def findNumbers(self, nums) -> int:
        total = 0
        for x in nums:
            d = 0
            tmp = x
            while tmp:
                d += 1
                tmp //= 10
            if d % 2 == 0:
                total += 1
        return total

