var findNumbers = function(nums) {
    let total = 0;
    for (const x of nums) {
        let d = 0, tmp = x;
        while (tmp > 0) { d++; tmp = Math.floor(tmp / 10); }
        if (d % 2 === 0) total++;
    }
    return total;
};
